class DevOpsAutomationAPI {
  private val service = new SystemAdministrationService()
  
  def handleCommandRequest(command: String, userInput: Seq[String]): CommandResult = {
    val request = CommandRequest(
      command = command,
      args = userInput
    )
    service.executeCommand(request)
  }
  
  def handleRawCommand(userInput: String): String = {
    service.executeRawCommand(userInput)
  }
  
  def handleComplexCommand(
    command: String,
    args: Seq[String],
    workingDir: Option[String],
    timeout: Option[Long],
    env: Map[String, String]
  ): CommandResult = {
    val request = CommandRequest(
      command = command,
      args = args,
      workingDir = workingDir,
      timeout = timeout,
      env = env
    )
    service.executeCommand(request)
  }
  
  def handlePipedCommands(commands: Seq[String]): CommandResult = {
    service.executePipedCommands(commands)
  }
  
  def dockerStatus(): CommandResult = {
    service.executeCommandWithParams("docker", "ps", "-a")
  }
  
  def kubernetesGetPods(namespace: String): CommandResult = {
    service.executeCommandWithParams("kubectl", "get", "pods", "-n", namespace)
  }
  
  def systemStatus(): CommandResult = {
    service.executeCommandWithParams("systemctl", "status")
  }
  
  def diskUsage(path: String): CommandResult = {
    service.executeCommandWithParams("du", "-sh", path)
  }
  
  def findFiles(directory: String, pattern: String): CommandResult = {
    service.executeCommandWithParams("find", directory, "-name", pattern)
  }
  
  def gitStatus(repoPath: String): CommandResult = {
    service.executeCommandInDirectory("git", repoPath, "status")
  }
  
  def buildProject(projectPath: String, buildTool: String): CommandResult = {
    buildTool match {
      case "sbt" => service.executeCommandInDirectory("sbt", projectPath, "compile")
      case "mvn" => service.executeCommandInDirectory("mvn", projectPath, "clean", "install")
      case _ => CommandResult(1, "", s"Unknown build tool: $buildTool", false)
    }
  }
}

